// State
let userCutoff = null;
let filteredColleges = [];
let currentPage = 1;
const PER_PAGE = 15;

// Build lookup structures
const collegeMap = {};
TNEA_DATA.forEach(d => {
  if (!collegeMap[d.code]) {
    collegeMap[d.code] = {code: d.code, name: d.name, rank: d.rank, type: d.type, district: d.district, branches: []};
  }
  collegeMap[d.code].branches.push(d);
});
const colleges = Object.values(collegeMap);

// Populate filters
function initFilters() {
  const distSel = document.getElementById('dist-filter');
  const dists = [...new Set(TNEA_DATA.map(d => d.district))].filter(Boolean).sort();
  dists.forEach(d => { const o = new Option(d, d); distSel.appendChild(o); });
  
  const branchSel = document.getElementById('branch-filter');
  const branches = [...new Set(TNEA_DATA.map(d => d.branch))].sort();
  const branchNames = {};
  TNEA_DATA.forEach(d => { branchNames[d.branch] = d.bname; });
  branches.forEach(b => { const o = new Option(`${b} – ${branchNames[b]}`, b); branchSel.appendChild(o); });
}

function calcCutoff() {
  const m = parseFloat(document.getElementById('maths').value) || 0;
  const p = parseFloat(document.getElementById('physics').value) || 0;
  const c = parseFloat(document.getElementById('chemistry').value) || 0;
  
  if (m === 0 && p === 0 && c === 0) { document.getElementById('score-area').style.display = 'none'; return 0; }
  
  const cutoff = Math.round((m/2 + p/4 + c/4) * 100) / 100;
  userCutoff = cutoff;
  
  document.getElementById('score-area').style.display = 'flex';
  document.getElementById('score-val').textContent = cutoff.toFixed(2);
  
  let band = '', tip = '';
  if (cutoff >= 195) { band = '🏆 Elite Band (195–200)'; tip = 'Anna University CEG, MIT, PSG, GCT — top colleges within reach!'; }
  else if (cutoff >= 185) { band = '⭐ Premium Band (185–195)'; tip = 'Excellent options in top 20 colleges available across most branches.'; }
  else if (cutoff >= 170) { band = '✅ Strong Band (170–185)'; tip = 'Good government and reputed autonomous colleges available. Prioritize rank over branch.'; }
  else if (cutoff >= 155) { band = '📌 Mid Band (155–170)'; tip = 'Focus on EA Rank top 100. Consider emerging branches over CSE competition.'; }
  else if (cutoff >= 140) { band = '⚠️ Lower Band (140–155)'; tip = 'Strongly recommended: Choose best-ranked college available, not just CSE/IT.'; }
  else { band = '🔴 Below 140'; tip = 'Prioritize accredited colleges with good placement. Government colleges offer better ROI.'; }
  
  document.getElementById('score-band').textContent = band;
  document.getElementById('score-tip').textContent = tip;
  return cutoff;
}

function predictColleges() {
  const c = calcCutoff();
  if (c > 0) {
    userCutoff = c;
    applyFilters();
  }
}

function getCutoff(d, cat) {
  return d[cat] ?? d['OC'];
}

function applyFilters() {
  const cat = document.getElementById('cat-filter').value;
  const dist = document.getElementById('dist-filter').value;
  const branch = document.getElementById('branch-filter').value;
  const group = document.getElementById('group-filter').value;
  const type = document.getElementById('type-filter').value;
  const maxRank = parseInt(document.getElementById('rank-filter').value) || Infinity;
  const sort = document.getElementById('sort-select').value;
  
  // Filter colleges
  let result = colleges.filter(col => {
    if (dist && col.district !== dist) return false;
    if (type && col.type !== type) return false;
    if (col.rank > maxRank) return false;
    
    const matchBranches = col.branches.filter(b => {
      if (branch && b.branch !== branch) return false;
      if (group && b.group !== group) return false;
      return true;
    });
    
    if (matchBranches.length === 0) return false;
    col._filtered_branches = matchBranches;
    return true;
  });
  
  // Compute best cutoff per college (for category)
  result.forEach(col => {
    const cvals = col._filtered_branches.map(b => getCutoff(b, cat)).filter(v => v !== null);
    col._best_cutoff = cvals.length ? Math.min(...cvals) : null;
    col._max_cutoff = cvals.length ? Math.max(...cvals) : null;
    if (userCutoff && col._best_cutoff !== null) {
      const diff = userCutoff - col._best_cutoff;
      if (diff >= 0) col._match = 'safe';
      else if (diff >= -5) col._match = 'close';
      else col._match = 'reach';
    } else { col._match = null; }
  });
  
  // Sort
  if (sort === 'match' && userCutoff) {
    result.sort((a, b) => {
      const order = {safe:0, close:1, reach:2, null:3};
      const mo = order[a._match] - order[b._match];
      if (mo !== 0) return mo;
      return (a._best_cutoff||999) - (b._best_cutoff||999);
    });
  } else if (sort === 'rank_asc') {
    result.sort((a, b) => (a.rank||999) - (b.rank||999));
  } else if (sort === 'cutoff_asc') {
    result.sort((a, b) => (a._best_cutoff||0) - (b._best_cutoff||0));
  } else if (sort === 'cutoff_desc') {
    result.sort((a, b) => (b._best_cutoff||0) - (a._best_cutoff||0));
  } else if (sort === 'name') {
    result.sort((a, b) => a.name.localeCompare(b.name));
  } else {
    result.sort((a, b) => (a.rank||999) - (b.rank||999));
  }
  
  filteredColleges = result;
  currentPage = 1;
  document.getElementById('results-info').innerHTML = `Showing <strong>${result.length}</strong> colleges`;
  renderPage();
}

function renderPage() {
  const cat = document.getElementById('cat-filter').value;
  const start = (currentPage - 1) * PER_PAGE;
  const end = start + PER_PAGE;
  const pageData = filteredColleges.slice(start, end);
  
  const container = document.getElementById('colleges-list');
  
  if (pageData.length === 0) {
    container.innerHTML = '<div class="empty"><div class="empty-icon">🔍</div><div>No colleges match your filters.<br><small>Try adjusting district, branch, or rank filters.</small></div></div>';
    document.getElementById('pagination').innerHTML = '';
    return;
  }
  
  container.innerHTML = pageData.map(col => renderCard(col, cat)).join('');
  renderPagination();
}

function getRankBadgeClass(rank) {
  if (!rank) return '';
  if (rank <= 10) return 'top10';
  if (rank <= 50) return 'top50';
  if (rank <= 100) return 'top100';
  if (rank <= 200) return 'top200';
  return '';
}

function getTypeClass(type) {
  if (type === 'Government') return 'badge-govt';
  if (type === 'Autonomous') return 'badge-auto';
  return 'badge-sf';
}

function renderCard(col, cat) {
  const matchBadge = col._match === 'safe' ? '<span class="match-safe">✓ Safe</span>' :
                     col._match === 'close' ? '<span class="match-close">~ Close</span>' :
                     col._match === 'reach' ? '<span class="match-reach">↑ Reach</span>' : '';
  
  const shortName = col.name.length > 80 ? col.name.substring(0, 77) + '...' : col.name;
  const rankBadgeClass = getRankBadgeClass(col.rank);
  
  const branchRows = (col._filtered_branches || col.branches).map(b => {
    const co = getCutoff(b, cat);
    let matchClass = '';
    if (userCutoff && co !== null) {
      const d = userCutoff - co;
      if (d >= 0) matchClass = 'match-highlight';
      else if (d >= -5) matchClass = 'highlight';
    }
    const valClass = co >= 185 ? 'cutoff-high' : co >= 160 ? 'cutoff-mid' : 'cutoff-low';
    return `<tr class="${matchClass}"><td><span class="branch-code">${b.branch}</span></td>
      <td>${b.bname}</td>
      <td><span class="cutoff-val ${valClass}">${co !== null ? co.toFixed(2) : '–'}</span></td>
      <td>${b.OC !== null ? b.OC.toFixed(2) : '–'}</td>
      <td>${b.BC !== null ? b.BC.toFixed(2) : '–'}</td>
      <td>${b.SC !== null ? b.SC.toFixed(2) : '–'}</td>
    </tr>`;
  }).join('');
  
  return `
  <div class="college-card">
    <div class="card-header" onclick="toggleCard('c${col.code}')">
      <div class="rank-badge ${rankBadgeClass}">${col.rank || '?'}</div>
      <div class="card-info">
        <div class="college-name">${shortName}</div>
        <div class="college-meta">
          <span class="badge ${getTypeClass(col.type)}">${col.type}</span>
          ${col.district ? `<span class="badge badge-district">📍 ${col.district}</span>` : ''}
          ${matchBadge}
        </div>
      </div>
      <div class="card-cutoff">
        <div class="best-cutoff">${col._best_cutoff !== null ? col._best_cutoff.toFixed(2) : '–'}</div>
        <div class="best-cutoff-lbl">${cat} Min Cutoff</div>
      </div>
      <div class="expand-btn" id="arr-c${col.code}">▼</div>
    </div>
    <div class="card-body" id="c${col.code}">
      <table class="branch-table">
        <thead><tr>
          <th>Code</th><th>Branch Name</th>
          <th>${cat} Cutoff</th><th>OC</th><th>BC</th><th>SC</th>
        </tr></thead>
        <tbody>${branchRows}</tbody>
      </table>
    </div>
  </div>`;
}

function toggleCard(id) {
  const el = document.getElementById(id);
  const arr = document.getElementById('arr-' + id);
  if (el.classList.contains('open')) {
    el.classList.remove('open');
    arr.textContent = '▼';
  } else {
    el.classList.add('open');
    arr.textContent = '▲';
  }
}

function renderPagination() {
  const total = Math.ceil(filteredColleges.length / PER_PAGE);
  if (total <= 1) { document.getElementById('pagination').innerHTML = ''; return; }
  
  let html = '';
  const start = Math.max(1, currentPage - 2);
  const end = Math.min(total, currentPage + 2);
  
  if (currentPage > 1) html += `<button class="page-btn" onclick="goPage(${currentPage-1})">‹ Prev</button>`;
  if (start > 1) html += `<button class="page-btn" onclick="goPage(1)">1</button>${start>2?'<span style="padding:8px">…</span>':''}`;
  
  for (let i = start; i <= end; i++) {
    html += `<button class="page-btn ${i===currentPage?'active':''}" onclick="goPage(${i})">${i}</button>`;
  }
  
  if (end < total) html += `${end<total-1?'<span style="padding:8px">…</span>':''}<button class="page-btn" onclick="goPage(${total})">${total}</button>`;
  if (currentPage < total) html += `<button class="page-btn" onclick="goPage(${currentPage+1})">Next ›</button>`;
  
  document.getElementById('pagination').innerHTML = html;
}

function goPage(p) {
  currentPage = p;
  renderPage();
  document.querySelector('.filters-bar').scrollIntoView({behavior:'smooth'});
}

function resetFilters() {
  document.getElementById('dist-filter').value = '';
  document.getElementById('branch-filter').value = '';
  document.getElementById('group-filter').value = '';
  document.getElementById('type-filter').value = '';
  document.getElementById('rank-filter').value = '';
  document.getElementById('sort-select').value = userCutoff ? 'match' : 'rank_asc';
  applyFilters();
}

function switchPage(page) {
  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-tab').forEach(t => t.classList.remove('active'));
  document.getElementById('page-' + page).classList.add('active');
  event.target.classList.add('active');
  if (page === 'insights') { buildMatrix(); }
}

// === INSIGHTS PAGE FUNCTIONS ===

function buildMatrix() {
  const cat = document.getElementById('matrix-cat').value;
  const maxRank = parseInt(document.getElementById('matrix-rank').value);
  
  // Get top colleges by rank
  const topColleges = colleges.filter(c => c.rank && c.rank <= maxRank)
                               .sort((a,b) => a.rank - b.rank)
                               .slice(0, Math.min(maxRank, 25));
  
  // Get key branches
  const keyBranches = ['CS','IT','AD','AI','EC','EE','ME','CE'];
  const branchNames = {};
  TNEA_DATA.forEach(d => { branchNames[d.branch] = d.bname; });
  
  let html = '<table class="matrix-tbl"><thead><tr>';
  html += '<th class="col-head" style="text-align:left;min-width:180px">College (EA Rank)</th>';
  keyBranches.forEach(b => {
    html += `<th class="cat-head">${b}<br><span style="font-size:0.7rem;font-weight:400">${branchNames[b]?.split(' ')[0] || ''}</span></th>`;
  });
  html += '</tr></thead><tbody>';
  
  topColleges.forEach(col => {
    const shortName = col.name.length > 50 ? col.name.substring(0,47)+'...' : col.name;
    html += `<tr><td style="text-align:left;font-weight:600;font-size:0.8rem">
      <span style="background:var(--primary);color:#fff;padding:1px 6px;border-radius:4px;font-size:0.7rem;margin-right:4px">#${col.rank}</span>${shortName}
    </td>`;
    
    keyBranches.forEach(b => {
      const branchData = col.branches.find(br => br.branch === b);
      if (branchData) {
        const cutoff = branchData[cat];
        if (cutoff !== null && cutoff !== undefined) {
          const cls = cutoff >= 185 ? 'heat-low' : cutoff >= 165 ? 'heat-med' : 'heat-high';
          html += `<td class="${cls}">${cutoff.toFixed(1)}</td>`;
        } else {
          html += `<td style="color:#ccc">–</td>`;
        }
      } else {
        html += `<td style="color:#ccc">–</td>`;
      }
    });
    html += '</tr>';
  });
  
  html += '</tbody></table>';
  html += `<div style="margin-top:12px;font-size:0.75rem;color:var(--text2);display:flex;gap:16px;flex-wrap:wrap">
    <span>🟩 Green = Lower cutoff (easier to get)</span>
    <span>🟨 Yellow = Moderate cutoff</span>
    <span>🟥 Red = High cutoff (competitive)</span>
    <span>– = Branch not available</span>
  </div>`;
  
  document.getElementById('matrix-container').innerHTML = html;
}

function buildComparison() {
  const cutoff = parseFloat(document.getElementById('cmp-cutoff').value);
  const cat = document.getElementById('cmp-cat').value;
  const maxRank = parseInt(document.getElementById('cmp-rank').value);
  
  if (!cutoff) { document.getElementById('compare-results').innerHTML = '<p style="color:var(--text2);font-size:0.85rem">Please enter your cutoff mark.</p>'; return; }
  
  const branchNames = {};
  TNEA_DATA.forEach(d => { branchNames[d.branch] = d.bname; });
  
  // For key branches, show top colleges where user can get in
  const keyBranches = ['CS','IT','AD','AI','EC','EE','ME','CE','BM','CB'];
  
  let rows = [];
  keyBranches.forEach(b => {
    const availColleges = colleges.filter(col => {
      if (col.rank > maxRank) return false;
      const br = col.branches.find(br2 => br2.branch === b);
      if (!br) return false;
      const co = br[cat];
      return co !== null && co !== undefined;
    });
    
    availColleges.sort((a,b2) => (a.rank||999) - (b2.rank||999));
    
    if (availColleges.length > 0) {
      const best = availColleges[0];
      const br = best.branches.find(br2 => br2.branch === b);
      const co = br[cat];
      const diff = cutoff - co;
      let status, statusClass;
      if (diff >= 5) { status = '✓ Safe'; statusClass = 'sb-safe'; }
      else if (diff >= 0) { status = '~ Close'; statusClass = 'sb-close'; }
      else if (diff >= -10) { status = '↑ Near'; statusClass = 'sb-close'; }
      else { status = '✗ Reach'; statusClass = 'sb-reach'; }
      
      // Best ranked college user can get
      const safeColleges = availColleges.filter(col => {
        const br2 = col.branches.find(br3 => br3.branch === b);
        return br2 && br2[cat] !== null && cutoff >= br2[cat];
      });
      
      const bestSafe = safeColleges.length > 0 ? safeColleges[0] : null;
      
      rows.push({
        branch: b, bname: branchNames[b] || b,
        bestRank: best.rank, bestCollege: best.name,
        bestCutoff: co, diff,
        bestSafeRank: bestSafe?.rank, bestSafeCollege: bestSafe?.name,
        status, statusClass, safeCount: safeColleges.length
      });
    }
  });
  
  rows.sort((a,b) => (a.bestSafeRank||999) - (b.bestSafeRank||999));
  
  let html = `<table class="compare-table"><thead><tr>
    <th>Branch</th><th>Best College (EA Rank)</th><th>${cat} Cutoff</th>
    <th>Your Gap</th><th>Best Safe College</th><th>Safe Options</th><th>Status</th>
  </tr></thead><tbody>`;
  
  rows.forEach(r => {
    const rankPillClass = r.bestRank <= 10 ? 'rp-1' : r.bestRank <= 25 ? 'rp-2' : r.bestRank <= 50 ? 'rp-3' : r.bestRank <= 100 ? 'rp-4' : 'rp-5';
    const safePillClass = r.bestSafeRank ? (r.bestSafeRank <= 10 ? 'rp-1' : r.bestSafeRank <= 25 ? 'rp-2' : r.bestSafeRank <= 50 ? 'rp-3' : 'rp-4') : 'rp-5';
    const gapText = r.diff >= 0 ? `+${r.diff.toFixed(1)}` : r.diff.toFixed(1);
    const gapColor = r.diff >= 0 ? 'var(--success)' : 'var(--danger)';
    const safeShort = r.bestSafeCollege ? (r.bestSafeCollege.length > 45 ? r.bestSafeCollege.substring(0,42)+'...' : r.bestSafeCollege) : 'None in range';
    const bestShort = r.bestCollege.length > 45 ? r.bestCollege.substring(0,42)+'...' : r.bestCollege;
    
    html += `<tr>
      <td><strong>${r.branch}</strong><br><span style="font-size:0.75rem;color:var(--text2)">${r.bname}</span></td>
      <td><span class="rank-pill ${rankPillClass}">#${r.bestRank}</span><br><span style="font-size:0.75rem">${bestShort}</span></td>
      <td style="font-weight:700">${r.bestCutoff.toFixed(2)}</td>
      <td style="font-weight:700;color:${gapColor}">${gapText}</td>
      <td>${r.bestSafeRank ? `<span class="rank-pill ${safePillClass}">#${r.bestSafeRank}</span><br><span style="font-size:0.73rem">${safeShort}</span>` : '<span style="color:var(--text2);font-size:0.8rem">No safe option</span>'}</td>
      <td style="text-align:center;font-weight:700;color:${r.safeCount > 3 ? 'var(--success)' : r.safeCount > 0 ? 'var(--warning)' : 'var(--danger)'}">${r.safeCount}</td>
      <td><span class="status-badge ${r.statusClass}">${r.status}</span></td>
    </tr>`;
  });
  
  html += '</tbody></table>';
  html += `<div style="margin-top:12px;padding:12px 16px;background:#eff6ff;border-radius:10px;font-size:0.8rem;color:var(--primary)">
    <strong>💡 Reading this table:</strong> Look for branches where your gap is positive (you qualify) at good-ranked colleges. 
    Compare "Best Safe College Rank" across branches — if CSE safe college is Rank 150 but ECE safe college is Rank 30, 
    <strong>ECE at the better college is the smarter choice!</strong>
  </div>`;
  
  document.getElementById('compare-results').innerHTML = html;
}

// Init
initFilters();
applyFilters();


